// and avoid top-level await (which breaks CJS output via esbuild).
// Functions that need them will fail at runtime in browser, but the module
// can be imported without error.

type RuntimeRequire = (specifier: string) => unknown;
type RuntimeCreateRequire = (baseUrl: string) => RuntimeRequire;
type NodeProcessWithBuiltinModule = NodeJS.Process & {
  getBuiltinModule?: (id: string) => unknown;
};
type NodeModuleBuiltin = {
  createRequire?: RuntimeCreateRequire;
};

function resolveRuntimeRequire(): RuntimeRequire | null {
  if (typeof require !== 'undefined') {
    return require as RuntimeRequire;
  }

  const runtimeProcess =
    typeof process !== 'undefined'
      ? (process as NodeProcessWithBuiltinModule)
      : null;
  const nodeModule = runtimeProcess?.getBuiltinModule?.(
    'module'
  ) as NodeModuleBuiltin | null | undefined;
  const createRequire =
    typeof nodeModule?.createRequire === 'function'
      ? nodeModule.createRequire
      : null;

  if (!createRequire || typeof import.meta === 'undefined' || !import.meta.url) {
    return null;
  }

  return createRequire(import.meta.url);
}

const nodeRequire = resolveRuntimeRequire();

function requireNodeModule<T>(specifier: string): T {
  if (!nodeRequire) {
    throw new Error(
      `Certified app filesystem integration requires a Node-compatible module loader for ${specifier}.`
    );
  }

  return nodeRequire(specifier) as T;
}

let _fsCache: typeof import('node:fs') | null = null;
// async function _getFs(): Promise<typeof import('node:fs')> {
//   if (!_fsCache) {
//     _fsCache = await import('node:fs');
//   }
//   return _fsCache;
// }
function getFsSync(): typeof import('node:fs') {
  try {
    if (!_fsCache) {
      _fsCache = requireNodeModule<typeof import('node:fs')>('node:fs');
    }
    return _fsCache;

  } catch (error) {
    throw new Error(`[getFsSync] ${error instanceof Error ? error.message : String(error)}`);
  }
}

let _pathCache: typeof import('node:path') | null = null;
function getPathSync(): typeof import('node:path') {
  try {
    if (!_pathCache) {
      _pathCache = requireNodeModule<typeof import('node:path')>('node:path');
    }
    return _pathCache;

  } catch (error) {
    throw new Error(`[getPathSync] ${error instanceof Error ? error.message : String(error)}`);
  }
}

let _parseGgProgram: typeof import('@a0n/aeon-logic')['parseGgProgram'] | null =
  null;
// async function _getParseGgProgram(): Promise<(typeof import('@a0n/aeon-logic'))['parseGgProgram']> {
//   if (!_parseGgProgram) {
//     const mod = await import('@a0n/aeon-logic');
//     _parseGgProgram = mod.parseGgProgram;
//   }
//   return _parseGgProgram;
// }
function getParseGgProgramSync(): typeof import('@a0n/aeon-logic')['parseGgProgram'] {
  try {
    if (!_parseGgProgram) {
      const mod = requireNodeModule<typeof import('@a0n/aeon-logic')>(
        '@a0n/aeon-logic'
      );
      _parseGgProgram = mod.parseGgProgram;
    }
    return _parseGgProgram;

  } catch (error) {
    throw new Error(`[getParseGgProgramSync] ${error instanceof Error ? error.message : String(error)}`);
  }
}
