const CERTIFIED_APP_CURRENT_ALIAS = 'current';

export type CertifiedAppAttestationKind =
  | 'vfs_snapshot'
  | 'deploy_build'
  | 'runtime_start'
  | 'publish_proof'
  | 'aeonpid_registration'
